-- FSC COC Audit document import (Drive-linked, source_url).
-- Mirrors import-ikea-iway-documents.sql: idempotent, re-runnable.
-- 102 files staged with metadata now; content_text backfilled progressively
-- in follow-up passes for AI Copilot grounding (same pattern as IKEA IWAY).
-- Excludes: Thumbs.db junk files, and 2 spreadsheets found in the 2026 Audit
-- Documents folder (MMDI employees_2026.xlsx, MMDI Sales_26072025-21012026.xlsx)
-- that are HR/financial data out of the approved scope.

on conflict (source_url) do update set
  content_text = excluded.content_text,
  file_size_bytes = excluded.file_size_bytes,
  uploaded_at = excluded.uploaded_at;